#!/usr/bin/env node
//
// One-shot migration: read `lib/imported-cases.ts` (which exports a
// TypeScript array literal), evaluate just the array body, and write
// the result to `public/data/imported-cases.json`.
//
// Why a runtime extract rather than parse-as-AST: the corpus is plain
// JSON-shaped after the `IMPORTED_CASES = [` opener — every value is
// already a literal (no expressions, no spread, no method calls). We
// strip the TypeScript wrapper, prepend `(`, append `)`, and run it
// through `eval`. Safe because the file is auto-generated by us, not
// untrusted input. If we ever hand-edit non-literal JS in there the
// extract will fail loudly.
//
// Usage:
//   node scripts/extract-imported-to-json.mjs
//
// Output:
//   public/data/imported-cases.json   (pretty-printed, 2-space indent)
//   stats line on stdout
//
// After running once, `lib/imported-cases.ts` can be deleted; the
// loader at `lib/seed-cases.ts` consumes the JSON directly going
// forward. Subsequent imports via `apply-twitter-import.mjs` should
// also write the JSON form (separate change).

import { readFileSync, writeFileSync, mkdirSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const HERE = dirname(fileURLToPath(import.meta.url));
const PROJECT = join(HERE, "..");
const TS_PATH = join(PROJECT, "lib", "imported-cases.ts");
const JSON_PATH = join(PROJECT, "public", "data", "imported-cases.json");

const raw = readFileSync(TS_PATH, "utf8");

// Slice between `IMPORTED_CASES: CaseRecord[] = [` and the closing `];`
// at the end of the file. Any text outside (banner comments, the
// `import type { CaseRecord }` line, the trailing newline) is
// stripped — only the array body survives.
const startMarker = "IMPORTED_CASES: CaseRecord[] = [";
const startIdx = raw.indexOf(startMarker);
if (startIdx < 0) {
  console.error(`[extract] could not find "${startMarker}" in ${TS_PATH}`);
  process.exit(1);
}
// The opening "[" of the array — eval will see "[ ... ];" so strip
// the trailing semicolon below.
const arrayBodyStart = raw.indexOf("[", startIdx + startMarker.indexOf("["));
const arrayBodyEnd = raw.lastIndexOf("];");
if (arrayBodyEnd < 0) {
  console.error("[extract] could not find closing `];`");
  process.exit(1);
}
const arrayLiteral = raw.slice(arrayBodyStart, arrayBodyEnd + 1);

// `eval` with parens to force expression context. The literal is
// pure data (objects, strings, numbers, arrays, booleans) — no
// function calls, no template literals with substitution.
let parsed;
try {
  parsed = eval(`(${arrayLiteral})`);
} catch (err) {
  console.error("[extract] eval failed:", err);
  process.exit(1);
}
if (!Array.isArray(parsed)) {
  console.error("[extract] expected an array, got:", typeof parsed);
  process.exit(1);
}

// Sanity: every entry should have `id`, `section`, `category`, `title`.
const bad = parsed.find(
  (c) =>
    typeof c?.id !== "string" ||
    typeof c?.section !== "string" ||
    typeof c?.category !== "string" ||
    typeof c?.title !== "string",
);
if (bad) {
  console.error("[extract] malformed case (missing required fields):", bad);
  process.exit(1);
}

mkdirSync(dirname(JSON_PATH), { recursive: true });
writeFileSync(JSON_PATH, JSON.stringify(parsed, null, 2) + "\n", "utf8");

const sizeKb = (Buffer.byteLength(JSON.stringify(parsed)) / 1024).toFixed(1);
console.log("=== extract-imported-to-json ===");
console.log(`Cases:    ${parsed.length}`);
console.log(`Output:   ${JSON_PATH}`);
console.log(`Size:     ${sizeKb} KB (minified — pretty-printed on disk)`);
